(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"gear-ratio-speed",fields:[{"key":"driverTeeth","label":"구동 기어 잇수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"drivenTeeth","label":"종동 기어 잇수","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"inputRpm","label":"입력 회전수 (RPM)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"마찰과 동력 손실을 무시한 이상적인 관계입니다.",compute:function(x){var d=Number(x.driverTeeth),o=Number(x.drivenTeeth),r=Number(x.inputRpm);if(![d,o,r].every(Number.isFinite)||d<=0||o<=0||r<0)return{error:"기어 잇수는 0보다 크게, 회전수는 0 이상으로 입력해 주세요."};var ratio=o/d;return{gearRatio:ratio,outputRpm:r/ratio,torqueMultiplier:ratio};},format:function(r,api){return api.resultCard("기어비",api.formatNumber(r.gearRatio,6)+":1","")+api.resultCard("출력 회전수",api.formatNumber(r.outputRpm,3)+" RPM","")+api.resultCard("이론 토크 배수",api.formatNumber(r.torqueMultiplier,6)+"배","");}},{id:"hydraulic-force",fields:[{"key":"inputForceN","label":"입력 힘 (N)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"inputAreaCm2","label":"입력 피스톤 면적 (cm²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"outputAreaCm2","label":"출력 피스톤 면적 (cm²)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"누설·마찰·구조 손실을 무시한 이상적인 파스칼 원리 계산입니다.",compute:function(x){var f=Number(x.inputForceN),a1=Number(x.inputAreaCm2),a2=Number(x.outputAreaCm2);if(![f,a1,a2].every(Number.isFinite)||f<0||a1<=0||a2<=0)return{error:"힘은 0 이상, 두 면적은 0보다 크게 입력해 주세요."};var pressure=f/(a1/10000),out=f*a2/a1;return{pressurePa:pressure,outputForceN:out,forceRatio:a2/a1};},format:function(r,api){return api.resultCard("출력 힘",api.formatNumber(r.outputForceN,3)+"N","")+api.resultCard("유압 압력",api.formatNumber(r.pressurePa,3)+"Pa","")+api.resultCard("힘 배율",api.formatNumber(r.forceRatio,6)+"배","");}},{id:"buoyant-force",fields:[{"key":"fluidDensity","label":"유체 밀도 (kg/m³)","type":"number","placeholder":"","default":"1000","options":[],"raw":false},{"key":"displacedVolume","label":"밀려난 부피 (m³)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"gravity","label":"중력가속도 (m/s²)","type":"number","placeholder":"","default":"9.80665","options":[],"raw":false}],hint:"",compute:function(x){var rho=Number(x.fluidDensity),v=Number(x.displacedVolume),g=Number(x.gravity);if(![rho,v,g].every(Number.isFinite)||rho<0||v<0||g<=0)return{error:"밀도와 부피는 0 이상, 중력가속도는 0보다 크게 입력해 주세요."};var mass=rho*v,force=mass*g;return{displacedMassKg:mass,buoyantForceN:force,equivalentKg:force/g};},format:function(r,api){return api.resultCard("부력",api.formatNumber(r.buoyantForceN,6)+"N","")+api.resultCard("밀려난 유체 질량",api.formatNumber(r.displacedMassKg,6)+"kg","")+api.resultCard("kgf 상당값",api.formatNumber(r.equivalentKg,6)+"kg","");}},{id:"heat-energy",fields:[{"key":"massKg","label":"질량 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"specificHeat","label":"비열 (J/kg·K)","type":"number","placeholder":"","default":"4186","options":[],"raw":false},{"key":"deltaTemperature","label":"온도 변화 (°C 또는 K)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"상변화와 열손실을 고려하지 않은 Q = mcΔT 계산입니다.",compute:function(x){var m=Number(x.massKg),c=Number(x.specificHeat),d=Number(x.deltaTemperature);if(![m,c,d].every(Number.isFinite)||m<0||c<0)return{error:"질량과 비열은 0 이상, 온도 변화는 숫자로 입력해 주세요."};var j=m*c*d;return{joules:j,kilojoules:j/1000,kwh:j/3600000};},format:function(r,api){return api.resultCard("열에너지",api.formatNumber(r.joules,3)+"J",api.formatNumber(r.kilojoules,6)+"kJ")+api.resultCard("전력량 환산",api.formatNumber(r.kwh,9)+"kWh","");}},{id:"decibel-ratio",fields:[{"key":"decibels","label":"데시벨 차이 (dB)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.decibels);if(!Number.isFinite(d))return{error:"데시벨 차이를 숫자로 입력해 주세요."};return{powerRatio:Math.pow(10,d/10),amplitudeRatio:Math.pow(10,d/20),decibels:d};},format:function(r,api){return api.resultCard("전력비",api.formatNumber(r.powerRatio,9)+"배","")+api.resultCard("진폭비",api.formatNumber(r.amplitudeRatio,9)+"배","")+api.resultCard("입력 차이",api.formatNumber(r.decibels,3)+"dB","");}},{id:"pulley-effort",fields:[{"key":"loadN","label":"하중 (N)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"supportingStrands","label":"하중을 지지하는 줄 수","type":"integer","placeholder":"","default":"2","options":[],"raw":false},{"key":"efficiency","label":"효율 (%)","type":"number","placeholder":"","default":"80","options":[],"raw":false}],hint:"줄과 도르래의 마찰·변형은 효율 값에 반영하세요.",compute:function(x){var l=Number(x.loadN),n=Number(x.supportingStrands),e=Number(x.efficiency)/100;if(!Number.isFinite(l)||l<0||!Number.isInteger(n)||n<=0||!Number.isFinite(e)||e<=0||e>1)return{error:"하중은 0 이상, 줄 수는 0보다 큰 정수, 효율은 0~100% 범위로 입력해 주세요."};var ideal=l/n,actual=l/(n*e);return{idealEffortN:ideal,actualEffortN:actual,idealMechanicalAdvantage:n,actualMechanicalAdvantage:n*e};},format:function(r,api){return api.resultCard("예상 필요 힘",api.formatNumber(r.actualEffortN,3)+"N","")+api.resultCard("이상적 필요 힘",api.formatNumber(r.idealEffortN,3)+"N","")+api.resultCard("실제 기계적 이득",api.formatNumber(r.actualMechanicalAdvantage,6)+"배","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
